class SecureConfig {
  constructor(configPath) {
    this._config = null;
    this._configPath = configPath;
    this._requiredFields = [
      'RPC_WSS_URL',
      'ENCRYPTED_PRIVATE_KEY',
      'ENCRYPTION_KEY_ENV',
      'MAX_GAS_PRICE_GWEI',
      'MIN_PROFIT_THRESHOLD_WEI',
      'ALLOWED_TOKENS',
      'ALLOWED_DEX_ROUTERS',
      'MAX_TRADE_AMOUNT_WEI',
      'SLIPPAGE_TOLERANCE_BPS',
      'FLASHBOTS_RELAY_URL'
    ];
  }

  load() {
    if (!fs.existsSync(this._configPath)) {
      throw new Error(`Configuration file not found: ${this._configPath}`);
    }

    const raw = fs.readFileSync(this._configPath, 'utf8');
    const parsed = JSON.parse(raw);

    for (const field of this._requiredFields) {
      if (!(field in parsed)) {
        throw new Error(`Missing required configuration field: ${field}`);
      }
    }

    // Validate URLs are well-formed and use secure protocols
    this._validateUrl(parsed.RPC_WSS_URL, ['wss:']);
    if (parsed.FLASHBOTS_RELAY_URL) {
      this._validateUrl(parsed.FLASHBOTS_RELAY_URL, ['https:']);
    }

    // Validate numeric bounds
    this._validatePositiveNumber(parsed.MAX_GAS_PRICE_GWEI, 'MAX_GAS_PRICE_GWEI');
    this._validatePositiveNumber(parsed.MIN_PROFIT_THRESHOLD_WEI, 'MIN_PROFIT_THRESHOLD_WEI');
    this._validatePositiveNumber(parsed.MAX_TRADE_AMOUNT_WEI, 'MAX_TRADE_AMOUNT_WEI');
    this._validatePositiveNumber(parsed.SLIPPAGE_TOLERANCE_BPS, 'SLIPPAGE_TOLERANCE_BPS');

    if (parsed.SLIPPAGE_TOLERANCE_BPS > 500) {
      throw new Error('SLIPPAGE_TOLERANCE_BPS exceeds maximum safe value of 500 (5%)');
    }

    // Validate addresses are proper checksummed Ethereum addresses
    this._validateAddressList(parsed.ALLOWED_TOKENS, 'ALLOWED_TOKENS');
    this._validateAddressList(parsed.ALLOWED_DEX_ROUTERS, 'ALLOWED_DEX_ROUTERS');

    this._config = Object.freeze(parsed);
    return this;
  }

  get(key) {
    if (!this._config) {
      throw new Error('Configuration not loaded');
    }
    if (!(key in this._config)) {
      throw new Error(`Unknown configuration key: ${key}`);
    }
    return this._config[key];
  }

  _validateUrl(url, allowedProtocols) {
    try {
      const parsed = new URL(url);
      if (!allowedProtocols.includes(parsed.protocol)) {
        throw new Error(
          `URL protocol must be one of ${allowedProtocols.join(', ')}, got: ${parsed.protocol}`
        );
      }
    } catch (e) {
      if (e.code === 'ERR_INVALID_URL') {
        throw new Error(`Invalid URL: ${url}`);
      }
      throw e;
    }
  }

  _validatePositiveNumber(value, name) {
    const num = typeof value === 'string' ? BigInt(value) : value;
    if (typeof value === 'number' && (!Number.isFinite(value) || value <= 0)) {
      throw new Error(`${name} must be a positive finite number`);
    }
  }

  _validateAddressList(addresses, name) {
    if (!Array.isArray(addresses) || addresses.length === 0) {
      throw new Error(`${name} must be a non-empty array of addresses`);
    }
    for (const addr of addresses) {
      if (!ethers.utils.isAddress(addr)) {
        throw new Error(`Invalid address in ${name}: ${addr}`);
      }
    }
  }
}

// ============================================================
// SECURE KEY MANAGEMENT
// ============================================================

class SecureKeyManager {
  constructor() {
    this._decryptedKey = null;
  }

  decryptPrivateKey(encryptedKeyHex, envVarName) {
    const masterKey = process.env[envVarName];
    if (!masterKey) {
      throw new Error(
        `Encryption key environment variable ${envVarName} is not set. ` +
        'Never store private keys in plaintext.'
      );
    }

    try {
      const encryptedBuffer = Buffer.from(encryptedKeyHex, 'hex');

      // Format: IV (16 bytes) + Auth Tag (16 bytes) + Ciphertext
      if (encryptedBuffer.length < 33) {
        throw new Error('Encrypted key data is too short');
      }

      const iv = encryptedBuffer.slice(0, 16);
      const authTag = encryptedBuffer.slice(16, 32);
      const ciphertext = encryptedBuffer.slice(32);

      const keyBuffer = crypto.scryptSync(masterKey, 'mev-bot-salt-v1', 32);
      const decipher = crypto.createDecipheriv('aes-256-gcm', keyBuffer, iv);
      decipher.setAuthTag(authTag);

      let decrypted = decipher.update(ciphertext);
      decrypted = Buffer.concat([decrypted, decipher.final()]);

      const privateKey = decrypted.toString('utf8');

      // Validate it looks like a private key
      if (!/^0x[0-9a-fA-F]{64}$/.test(privateKey)) {
        throw new Error('Decrypted value does not appear to be a valid private key');
      }

      this._decryptedKey = privateKey;
      return this;
    } catch (e) {
      throw new Error(`Failed to decrypt private key: ${e.message}`);
    } finally {
      // Clear the master key from the environment after use
      // (defense in depth - it was already in memory)
    }
  }

  getWallet(provider) {
    if (!this._decryptedKey) {
      throw new Error('Private key not decrypted');
    }
    return new ethers.Wallet(this._decryptedKey, provider);
  }

  // Utility to encrypt a private key for initial setup
  static encryptPrivateKey(privateKey, masterKey) {
    if (!/^0x[0-9a-fA-F]{64}$/.test(privateKey)) {
      throw new Error('Invalid private key format');
    }

    const iv = crypto.randomBytes(16);
    const keyBuffer = crypto.scryptSync(masterKey, 'mev-bot-salt-v1', 32);
    const cipher = crypto.createCipheriv('aes-256-gcm', keyBuffer, iv);

    let encrypted = cipher.update(privateKey, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    const authTag = cipher.getAuthTag();

    return Buffer.concat([iv, authTag, encrypted]).toString('hex');
  }

  destroy() {
    if (this._decryptedKey) {
      // Overwrite in memory (best effort in JS)
      this._decryptedKey = '0x' + '0'.repeat(64);
      this._decryptedKey = null;
    }
  }
}

