class SecureLogger {
  static _sensitivePatterns = [
    /0x[0-9a-fA-F]{64}/g,  // Private keys
    /password/gi,
    /secret/gi,
    /mnemonic/gi,
  ];

  static _sanitize(message) {
    let sanitized = String(message);
    // Redact anything that looks like a private key
    sanitized = sanitized.replace(/0x[0-9a-fA-F]{64}/g, '0x[REDACTED_KEY]');
    return sanitized;
  }

  static info(message, data = {}) {
    const sanitizedData = {};
    for (const [key, value] of Object.entries(data)) {
      sanitizedData[key] = SecureLogger._sanitize(String(value));
    }
    console.log(JSON.stringify({
      level: 'INFO',
      timestamp: new Date().toISOString(),
      message: SecureLogger._sanitize(message),
      ...sanitizedData
    }));
  }

  static warn(message, data = {}) {
    const sanitizedData = {};
    for (const [key, value] of Object.entries(data)) {
      sanitizedData[key] = SecureLogger._sanitize(String(value));
    }
    console.warn(JSON.stringify({
      level: 'WARN',
      timestamp: new Date().toISOString(),
      message: SecureLogger._sanitize(message),
      ...sanitizedData
    }));
  }

  static error(message, data = {}) {
    const sanitizedData = {};
    for (const [key, value] of Object.entries(data)) {
      sanitizedData[key] = SecureLogger._sanitize(String(value));
    }
    console.error(JSON.stringify({
      level: 'ERROR',
      timestamp: new Date().toISOString(),
      message: SecureLogger._sanitize(message),
      ...sanitizedData
    }));
  }
}

