class TransactionValidator {
  constructor(config) {
    this._allowedTokens = new Set(
      config.get('ALLOWED_TOKENS').map(addr => ethers.utils.getAddress(addr).toLowerCase())
    );
    this._allowedRouters = new Set(
      config.get('ALLOWED_DEX_ROUTERS').map(addr => ethers.utils.getAddress(addr).toLowerCase())
    );
    this._maxGasPriceWei = ethers.utils.parseUnits(
      String(config.get('MAX_GAS_PRICE_GWEI')), 'gwei'
    );
    this._maxTradeAmountWei = ethers.BigNumber.from(config.get('MAX_TRADE_AMOUNT_WEI'));
    this._minProfitWei = ethers.BigNumber.from(config.get('MIN_PROFIT_THRESHOLD_WEI'));
    this._slippageBps = config.get('SLIPPAGE_TOLERANCE_BPS');
  }

  isAllowedToken(address) {
    try {
      const normalized = ethers.utils.getAddress(address).toLowerCase();
      return this._allowedTokens.has(normalized);
    } catch {
      return false;
    }
  }

  isAllowedRouter(address) {
    try {
      const normalized = ethers.utils.getAddress(address).toLowerCase();
      return this._allowedRouters.has(normalized);
    } catch {
      return false;
    }
  }

  validateGasPrice(gasPriceWei) {
    const gasPrice = ethers.BigNumber.from(gasPriceWei);
    if (gasPrice.gt(this._maxGasPriceWei)) {
      SecureLogger.warn('Gas price exceeds maximum', {
        gasPrice: gasPrice.toString(),
        maxGasPrice: this._maxGasPriceWei.toString()
      });
      return false;
    }
    return true;
  }

  validateTradeAmount(amountWei) {
    const amount = ethers.BigNumber.from(amountWei);
    if (amount.gt(this._maxTradeAmountWei)) {
      SecureLogger.warn('Trade amount exceeds maximum', {
        amount: amount.toString(),
        maxAmount: this._maxTradeAmountWei.toString()
      });
      return false;
    }
    if (amount.lte(0)) {
      return false;
    }
    return true;
  }

  validateProfitability(expectedProfitWei, gasCostWei) {
    const profit = ethers.BigNumber.from(expectedProfitWei);
    const gasCost = ethers.BigNumber.from(gasCostWei);
    const netProfit = profit.sub(gasCost);

    if (netProfit.lt(this._minProfitWei)) {
      return { profitable: false, netProfit };
    }
    return { profitable: true, netProfit };
  }

  calculateMinOutput(expectedOutput) {
    const output = ethers.BigNumber.from(expectedOutput);
    // Apply slippage tolerance
    const minOutput = output.mul(10000 - this._slippageBps).div(10000);
    return minOutput;
  }
}

