const UNISWAP_V2_ROUTER_ABI = [
  'function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts)',
  'function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)',
  'function swapExactETHForTokens(uint amountOutMin, address[] calldata path, address to, uint deadline) external payable returns (uint[] memory amounts)',
  'function swapExactTokensForETH(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)',
];

const ERC20_ABI = [
  'function approve(address spender, uint256 amount) external returns (bool)',
  'function balanceOf(address account) external view returns (uint256)',
  'function allowance(address owner, address spender) external view returns (uint256)',
];

// Known swap function selectors for mempool monitoring
const SWAP_SELECTORS = Object.freeze({
  '0x38ed1739': 'swapExactTokensForTokens',
  '0x8803dbee': 'swapTokensForExactTokens',
  '0x7ff36ab5': 'swapExactETHForTokens',
  '0xfb3bdb41': 'swapETHForExactTokens',
  '0x18cbafe5': 'swapExactTokensForETH',
  '0x4a25d94a': 'swapTokensForExactETH',
});

// ============================================================
// ARBITRAGE OPPORTUNITY DETECTOR
// ============================================================

class ArbitrageDetector {
  constructor(provider, config, validator) {
    this._provider = provider;
    this._config = config;
    this._validator = validator;
    this._routerContracts = new Map();
    this._iface = new ethers.utils.Interface(UNISWAP_V2_ROUTER_ABI);

    // Initialize router contract instances for allowed routers only
    for (const routerAddr of config.get('ALLOWED_DEX_ROUTERS')) {
      const normalized = ethers.utils.getAddress(routerAddr);
      this._routerContracts.set(
        normalized.toLowerCase(),
        new ethers.Contract(normalized, UNISWAP_V2_ROUTER_ABI, provider)
      );
    }
  }

  decodePendingSwap(tx) {
    if (!tx || !tx.data || tx.data.length < 10) {
      return null;
    }

    const selector = tx.data.slice(0, 10);
    const swapType = SWAP_SELECTORS[selector];

    if (!swapType) {
      return null;
    }

    // Validate the target is an allowed router
    if (!this._validator.isAllowedRouter(tx.to)) {
      return null;
    }

    try {
      const decoded = this._iface.decodeFunctionData(swapType, tx.data);

      let path;
      let amountIn;

      switch (swapType) {
        case 'swapExactTokensForTokens':
        case 'swapExactTokensForETH':
          amountIn = decoded.amountIn || decoded[0];
          path = decoded.path || decoded[2];
          break;
        case 'swapExactETHForTokens':
          amountIn = tx.value;
          path = decoded.path || decoded[1];
          break;
        case 'swapTokensForExactTokens':
        case 'swapTokensForExactETH':
        case 'swapETHForExactTokens':
          amountIn = decoded.amountInMax || decoded[1] || tx.value;
          path = decoded.path || decoded[2];
          break;
        default:
          return null;
      }

      // Validate all tokens in path are in our allowlist
      if (!Array.isArray(path)) {
        return null;
      }

      for (const token of path) {
        if (!this._validator.isAllowedToken(token)) {
          SecureLogger.info('Skipping swap with non-allowlisted token', {
            token: token
          });
          return null;
        }
      }

      // Validate amount
      if (!this._validator.validateTradeAmount(amountIn)) {
        return null;
      }

      return {
        swapType,
        amountIn: ethers.BigNumber.from(amountIn),
        path: path.map(addr => ethers.utils.getAddress(addr)),
        router: ethers.utils.getAddress(tx.to),
        gasPrice: tx.gasPrice ? ethers.BigNumber.from(tx.gasPrice) : null,
        maxFeePerGas: tx.maxFeePerGas ? ethers.BigNumber.from(tx.maxFeePerGas) : null,
        txHash: tx.hash,
      };
    } catch (e) {
      SecureLogger.warn('Failed to decode swap transaction', {
        error: e.message,
        txHash: tx.hash
      });
      return null;
    }
  }

  async findArbitrageOpportunity(swapInfo) {
    const opportunities = [];

    // Check price across different DEX routers for the same path
    const routerEntries = Array.from(this._routerContracts.entries());

    for (const [routerAddrLower, routerContract] of routerEntries) {
      const routerAddr = ethers.utils.getAddress(routerAddrLower);

      // Skip the same router the original tx targets
      if (routerAddr.toLowerCase() === swapInfo.router.toLowerCase()) {
        continue;
      }

      try {
        // Check forward path price
        const forwardAmounts = await routerContract.getAmountsOut(
          swapInfo.amountIn,
          swapInfo.path,
          { blockTag: 'pending' }
        );

        // Check reverse path price on original router
        const reversePath = [...swapInfo.path].reverse();
        const originalRouter = this._routerContracts.get(swapInfo.router.toLowerCase());

        if (!originalRouter) {
          continue;
        }

        const outputFromForward = forwardAmounts[forwardAmounts.length - 1];

        const reverseAmounts = await originalRouter.getAmountsOut(
          outputFromForward,
          reversePath,
          { blockTag: 'pending' }
        );

        const finalOutput = reverseAmounts[reverseAmounts.length - 1];
        const grossProfit = finalOutput.sub(swapInfo.amountIn);

        if (grossProfit.gt(0)) {
          opportunities.push({
            buyRouter: routerAddr,
            sellRouter: swapInfo.router,
            path: swapInfo.path,
            reversePath,
            amountIn: swapInfo.amountIn,
            expectedOutput: finalOutput,
            grossProfit,
            buyAmountsOut: forwardAmounts,
            sellAmountsOut: reverseAmounts,
          });
        }
      } catch (e) {
        // Price query failed - pair may not exist on this DEX
        SecureLogger.info('Price query failed for router', {
          router: routerAddr,
          error: e.message
        });
      }
    }

    return opportunities;
  }
}

// ============================================================
// FLASHBOTS BUNDLE SUBMITTER (private transaction submission)
// ============================================================

class FlashbotsSubmitter {
  constructor(config, wallet) {
    this._relayUrl = config.get('FLASHBOTS_RELAY_URL');
    this._wallet = wallet;
    this._authSigner = wallet; // In production, use a separate auth key
  }

  async submitBundle(signedTransactions, targetBlockNumber) {
    // Use Flashbots to submit transactions privately
    // This prevents our transactions from being front-run in the public mempool
    const body = {
      jsonrpc: '2.0',
      id: 1,
      method: 'eth_sendBundle',
      params: [{
        txs: signedTransactions,
        blockNumber: ethers.utils.hexValue(targetBlockNumber),
      }]
    };

    const bodyStr = JSON.stringify(body);

    // Sign the request for Flashbots authentication
    const signature = await this._authSigner.signMessage(
      ethers.utils.id(bodyStr)
    );

    const response = await fetch(this._relayUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Flashbots-Signature': `${this._wallet.address}:${signature}`,
      },
      body: bodyStr,
    });

    if (!response.ok) {
      throw new Error(`Flashbots relay returned ${response.status}: ${await response.text()}`);
    }

    const result = await response.json();

    if (result.error) {
      throw new Error(`Flashbots error: ${JSON.stringify(result.error)}`);
    }

    return result;
  }

  async simulateBundle(signedTransactions, blockNumber) {
    const body = {
      jsonrpc: '2.0',
      id: 1,
      method: 'eth_callBundle',
      params: [{
        txs: signedTransactions,
        blockNumber: ethers.utils.hexValue(blockNumber),
        stateBlockNumber: 'latest',
      }]
    };

    const bodyStr = JSON.stringify(body);
    const signature = await this._authSigner.signMessage(
      ethers.utils.id(bodyStr)
    );

    const response = await fetch(this._relayUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Flashbots-Signature': `${this._wallet.address}:${signature}`,
      },
      body: bodyStr,
    });

    if (!response.ok) {
      throw new Error(`Flashbots simulation failed: ${response.status}`);
    }

    return await response.json();
  }
}

// ============================================================
// RATE LIMITER
// ============================================================

class RateLimiter {
  constructor(maxRequests, windowMs) {
    this._maxRequests = maxRequests;
    this._windowMs = windowMs;
    this._timestamps = [];
  }

  canProceed() {
    const now = Date.now();
    this._timestamps = this._timestamps.filter(t => now - t < this._windowMs);

    if (this._timestamps.length >= this._maxRequests) {
      return false;
    }

    this._timestamps.push(now);
    return true;
  }
}

// ============================================================
// CIRCUIT BREAKER
// ============================================================

class CircuitBreaker {
  constructor(failureThreshold, resetTimeMs) {
    this._failureThreshold = failureThreshold;
    this._resetTimeMs = resetTimeMs;
    this._failures = 0;
    this._lastFailureTime = 0;
    this._state = 'CLOSED'; // CLOSED = operational, OPEN = tripped
  }

  recordFailure() {
    this._failures++;
    this._lastFailureTime = Date.now();

    if (this._failures >= this._failureThreshold) {
      this._state = 'OPEN';
      SecureLogger.warn('Circuit breaker OPENED', {
        failures: this._failures,
        threshold: this._failureThreshold
      });
    }
  }

  recordSuccess() {
    this._failures = 0;
    this._state = 'CLOSED';
  }

  isOpen() {
    if (this._state === 'OPEN') {
      // Check if reset time has elapsed
      if (Date.now() - this._lastFailureTime > this._resetTimeMs) {
        this._state = 'HALF_OPEN';
        SecureLogger.info('Circuit breaker HALF_OPEN, allowing test request');
        return false;
      }
      return true;
    }
    return false;
  }
}

// ============================================================
// NONCE MANAGER
// ============================================================

class NonceManager {
  constructor(provider, address) {
    this._provider = provider;
    this._address = address;
    this._currentNonce = null;
    this._mutex = false;
  }

  async getNonce() {
    // Simple mutex to prevent race conditions
    while (this._mutex) {
      await new Promise(resolve => setTimeout(resolve, 10));
    }
    this._mutex = true;

    try {
      if (this._currentNonce === null) {
        this._currentNonce = await this._provider.getTransactionCount(
          this._address, 'pending'
        );
      }
      const nonce = this._currentNonce;
      this._currentNonce++;
      return nonce;
    } finally {
      this._mutex = false;
    }
  }

  async reset() {
    this._currentNonce = null;
  }
}

