class MEVArbitrageBot {
  constructor(configPath) {
    this._config = new SecureConfig(configPath).load();
    this._keyManager = new SecureKeyManager();
    this._provider = null;
    this._wsProvider = null;
    this._wallet = null;
    this._detector = null;
    this._validator = null;
    this._flashbots = null;
    this._nonceManager = null;
    this._rateLimiter = new RateLimiter(50, 60000); // 50 ops per minute
    this._circuitBreaker = new CircuitBreaker(5, 300000); // 5 failures, 5 min reset
    this._isRunning = false;
    this._pendingTxSubscription = null;
    this._processedTxHashes = new Set();
    this._maxProcessedCacheSize = 10000;
  }

  async initialize() {
    SecureLogger.info('Initializing MEV Arbitrage Bot');

    // Decrypt private key from encrypted storage
    this._keyManager.decryptPrivateKey(
      this._config.get('ENCRYPTED_PRIVATE_KEY'),
      this._config.get('ENCRYPTION_KEY_ENV')
    );

    // Set up providers
    this._wsProvider = new ethers.providers.WebSocketProvider(
      this._config.get('RPC_WSS_URL')
    );

    this._provider = this._wsProvider;

    // Create wallet (private key never logged or exposed)
    this._wallet = this._keyManager.getWallet(this._provider);

    SecureLogger.info('Wallet initialized', {
      address: this._wallet.address
    });

    // Initialize components
    this._validator = new TransactionValidator(this._config);
    this._detector = new ArbitrageDetector(this._provider, this._config, this._validator);
    this._flashbots = new FlashbotsSubmitter(this._config, this._wallet);
    this._nonceManager = new NonceManager(this._provider, this._wallet.address);

    // Verify wallet has sufficient balance
    const balance = await this._provider.getBalance(this._wallet.address);
    SecureLogger.info('Wallet balance', {
      balanceETH: ethers.utils.formatEther(balance)
    });

    if (balance.lt(ethers.utils.parseEther('0.01'))) {
      SecureLogger.warn('Low wallet balance - may not be able to cover gas costs');
    }

    return this;
  }

  async start() {
    if (this._isRunning) {
      SecureLogger.warn('Bot is already running');
      return;
    }

    this._isRunning = true;
    SecureLogger.info('Starting mempool monitoring');

    // Subscribe to pending transactions
    this._wsProvider.on('pending', async (txHash) => {
      if (!this._isRunning) return;

      // Deduplicate
      if (this._processedTxHashes.has(txHash)) return;
      this._addProcessedTx(txHash);

      // Rate limiting
      if (!this._rateLimiter.canProceed()) {
        return;
      }

      // Circuit breaker
      if (this._circuitBreaker.isOpen()) {
        return;
      }

      try {
        await this._processPendingTransaction(txHash);
      } catch (e) {
        SecureLogger.error('Error processing pending transaction', {
          txHash,
          error: e.message
        });
        this._circuitBreaker.recordFailure();
      }
    });

    // Handle WebSocket disconnection
    this._wsProvider._websocket.on('close', () => {
      if (this._isRunning) {
        SecureLogger.warn('WebSocket disconnected, attempting reconnection');
        this._reconnect();
      }
    });

    // Handle errors
    this._wsProvider.on('error', (error) => {
      SecureLogger.error('Provider error', { error: error.message });
      this._circuitBreaker.recordFailure();
    });

    SecureLogger.info('Bot is now monitoring the mempool');
  }

  async _processPendingTransaction(txHash) {
    // Fetch the full transaction
    const tx = await this._provider.getTransaction(txHash);

    if (!tx || !tx.to) return;

    // Decode if it's a swap
    const swapInfo = this._detector.decodePendingSwap(tx);
    if (!swapInfo) return;

    SecureLogger.info('Detected swap transaction', {
      txHash: tx.hash,
      swapType: swapInfo.swapType,
      router: swapInfo.router,
      amountIn: swapInfo.amountIn.toString(),
      pathLength: swapInfo.path.length,
    });

    // Find arbitrage opportunities
    const opportunities = await this._detector.findArbitrageOpportunity(swapInfo);

    if (opportunities.length === 0) return;

    // Evaluate each opportunity
    for (const opp of opportunities) {
      await this._evaluateAndExecute(opp, swapInfo);
    }
  }

  async _evaluateAndExecute(opportunity, originalSwap) {
    // Estimate gas cost
    const gasEstimate = ethers.BigNumber.from(300000); // Conservative estimate
    const currentGasPrice = await this._provider.getGasPrice();

    // Don't exceed our max gas price
    if (!this._validator.validateGasPrice(currentGasPrice)) {
      SecureLogger.info('Skipping - gas price too high');
      return;
    }

    const gasCost = gasEstimate.mul(currentGasPrice);

    // Check profitability after gas
    const { profitable, netProfit } = this._validator.validateProfitability(
      opportunity.grossProfit,
      gasCost
    );

    if (!profitable) {
      SecureLogger.info('Opportunity not profitable after gas', {
        grossProfit: opportunity.grossProfit.toString(),
        gasCost: gasCost.toString(),
        netProfit: netProfit.toString()
      });
      return;
    }

    SecureLogger.info('Profitable arbitrage found!', {
      netProfit: ethers.utils.formatEther(netProfit),
      buyRouter: opportunity.buyRouter,
      sellRouter: opportunity.sellRouter,
    });

    // Build and submit via Flashbots (private submission to prevent front-running of our tx)
    await this._executeArbitrage(opportunity, currentGasPrice, gasEstimate);
  }

  async _executeArbitrage(opportunity, gasPrice, gasEstimate) {
    try {
      const nonce = await this._nonceManager.getNonce();
      const blockNumber = await this._provider.getBlockNumber();
      const targetBlock = blockNumber + 1;
      const deadline = Math.floor(Date.now() / 1000) + 120; // 2 minute deadline

      // Calculate minimum output with slippage protection
      const minOutputBuy = this._validator.calculateMinOutput(
        opportunity.buyAmountsOut[opportunity.buyAmountsOut.length - 1]
      );
      const minOutputSell = this._validator.calculateMinOutput(
        opportunity.sellAmountsOut[opportunity.sellAmountsOut.length - 1]
      );

      // Build buy transaction
      const buyRouterContract = new ethers.Contract(
        opportunity.buyRouter,
        UNISWAP_V2_ROUTER_ABI,
        this._wallet
      );

      const buyTxData = buyRouterContract.interface.encodeFunctionData(
        'swapExactTokensForTokens',
        [
          opportunity.amountIn,
          minOutputBuy,
          opportunity.path,
          this._wallet.address,
          deadline,
        ]
      );

      // Build sell transaction
      const sellRouterContract = new ethers.Contract(
        opportunity.sellRouter,
        UNISWAP_V2_ROUTER_ABI,
        this._wallet
      );

      const sellTxData = sellRouterContract.interface.encodeFunctionData(
        'swapExactTokensForTokens',
        [
          minOutputBuy, // Use the minimum we expect from buy
          minOutputSell,
          opportunity.reversePath,
          this._wallet.address,
          deadline,
        ]
      );

      // Sign transactions
      const buyTx = await this._wallet.signTransaction({
        to: opportunity.buyRouter,
        data: buyTxData,
        gasLimit: gasEstimate,
        gasPrice: gasPrice,
        nonce: nonce,
        chainId: (await this._provider.getNetwork()).chainId,
      });

      const sellNonce = nonce + 1;
      const sellTx = await this._wallet.signTransaction({
        to: opportunity.sellRouter,
        data: sellTxData,
        gasLimit: gasEstimate,
        gasPrice: gasPrice,
        nonce: sellNonce,
        chainId: (await this._provider.getNetwork()).chainId,
      });

      // Simulate first via Flashbots
      SecureLogger.info('Simulating bundle via Flashbots');
      const simulation = await this._flashbots.simulateBundle(
        [buyTx, sellTx],
        blockNumber
      );

      if (simulation.error || (simulation.result && simulation.result.firstRevert)) {
        SecureLogger.warn('Bundle simulation failed or reverted', {
          error: JSON.stringify(simulation.error || simulation.result.firstRevert)
        });
        await this._nonceManager.reset();
        return;
      }

      // Submit bundle privately via Flashbots
      SecureLogger.info('Submitting bundle via Flashbots', {
        targetBlock: targetBlock
      });

      const result = await this._flashbots.submitBundle(
        [buyTx, sellTx],
        targetBlock
      );

      SecureLogger.info('Bundle submitted successfully', {
        bundleHash: result.result?.bundleHash || 'unknown'
      });

      this._circuitBreaker.recordSuccess();

    } catch (e) {
      SecureLogger.error('Failed to execute arbitrage', {
        error: e.message
      });
      this._circuitBreaker.recordFailure();
      await this._nonceManager.reset();
    }
  }

  _addProcessedTx(txHash) {
    this._processedTxHashes.add(txHash);
    // Prevent unbounded memory growth
    if (this._processedTxHashes.size > this._maxProcessedCacheSize) {
      const iterator = this._processedTxHashes.values();
      // Remove oldest 20%
      const toRemove = Math.floor(this._maxProcessedCacheSize * 0.2);
      for (let i = 0; i < toRemove; i++) {
        this._processedTxHashes.delete(iterator.next().value);
      }
    }
  }

  async _reconnect() {
    const maxRetries = 5;
    let retryCount = 0;
    const baseDelay = 1000;

    while (retryCount < maxRetries && this._isRunning) {
      retryCount++;
      const delay = baseDelay * Math.pow(2, retryCount - 1); // Exponential backoff
      SecureLogger.info(`Reconnection attempt ${retryCount}/${maxRetries} in ${delay}ms`);

      await new Promise(resolve => setTimeout(resolve, delay));

      try {
        this._wsProvider = new ethers.providers.WebSocketProvider(
          this._config.get('RPC_WSS_URL')
        );
        this._provider = this._wsProvider;
        this._wallet = this._keyManager.getWallet(this._provider);
        this._detector = new ArbitrageDetector(this._provider, this._config, this._validator);
        this._nonceManager = new NonceManager(this._provider, this._wallet.address);

        await this._wsProvider.ready;
        SecureLogger.info('Reconnected successfully');

        // Restart monitoring
        await this.start();
        return;
      } catch (e) {
        SecureLogger.error('Reconnection failed', { error: e.message });
      }
    }

    SecureLogger.error('Max reconnection attempts reached, shutting down');
    await this.stop();
  }

  async stop() {
    SecureLogger.info('Stopping MEV Arbitrage Bot');
    this._isRunning = false;

    if (this._wsProvider) {
      this._wsProvider.removeAllListeners();
      await this._wsProvider.destroy();
    }

    // Securely destroy key material
    this._keyManager.destroy();

    SecureLogger.info('Bot stopped');
  }
}

// ============================================================
// GRACEFUL SHUTDOWN
// ============================================================

let botInstance = null;

async function gracefulShutdown(signal) {
  SecureLogger.info(`Received ${signal}, initiating graceful shutdown`);
  if (botInstance) {
    await botInstance.stop();
  }
  process.exit(0);
}

process.on('SIGINT', () => gracefulShutdown('SIGINT'));
process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('uncaughtException', (error) => {
  SecureLogger.error('Uncaught exception', { error: error.message });
  gracefulShutdown('uncaughtException');
});
process.on('unhandledRejection', (reason) => {
  SecureLogger.error('Unhandled rejection', { error: String(reason) });
});

// ============================================================
// ENTRY POINT
// ============================================================

async function main() {
  const configPath = process.argv[2] || path.join(__dirname, 'config.json');

  SecureLogger.info('MEV Arbitrage Bot starting', { configPath });

  botInstance = new MEVArbitrageBot(configPath);
  await botInstance.initialize();
  await botInstance.start();
}

// ============================================================
// KEY ENCRYPTION UTILITY (run separately to set up encrypted key)
// ============================================================

async function encryptKeyUtility() {
  if (process.argv[2] !== '--encrypt-key') return false;

  const readline = require('readline');
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
  });

  const question = (prompt) => new Promise(resolve => rl.question(prompt, resolve));

  try {
    const privateKey = await question('Enter private key (0x...): ');
    const masterKey = await question('Enter master encryption password: ');

    const encrypted = SecureKeyManager.encryptPrivateKey(privateKey, masterKey);
    console.log('\nEncrypted key (store in config as ENCRYPTED_PRIVATE_KEY):');
    console.log(encrypted);
    console.log('\nSet your master password as the environment variable specified in ENCRYPTION_KEY_ENV');
  } finally {
    rl.close();
  }

  return true;
}

// Run
(async () => {
  try {
    const isUtility = await encryptKeyUtility();
    if (!isUtility) {
      await main();
    }
  } catch (e) {
    SecureLogger.error('Fatal error', { error: e.message });
    process.exit(1);
  }
})();

module.exports = {
  MEVArbitrageBot,
  SecureConfig,
  SecureKeyManager,
  SecureLogger,
  TransactionValidator,
  ArbitrageDetector,
  FlashbotsSubmitter,
  RateLimiter,
  CircuitBreaker,
};